@@ -0,0 +1,41 @@
+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Handler (ID 30185).
+/// Handles clearing Shopify-specific fields when copying sales documents.
+/// </summary>
+codeunit 30185 "Shpfy Copy Document Handler"
+{
+    /// <summary>
+    /// Clears Shopify Order Id and Shopify Order No. when copying a posted sales invoice.
+    /// This ensures that copied invoices can be synced independently to Shopify.
+    /// </summary>
+    /// <param name="ToSalesHeader">The target Sales Header to clear Shopify fields from.</param>
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnCopySalesHeaderFromPostedInvoiceClearExtFields', '', false, false)]
+    local procedure OnCopySalesHeaderFromPostedInvoiceClearExtFields(var ToSalesHeader: Record "Sales Header")
+    var
+        FieldRef: FieldRef;
+        RecordRef: RecordRef;
+    begin
+        // Clear Shopify Order Id and Shopify Order No. fields when copying documents
+        // These fields should not be copied to avoid sync issues with Shopify
+        RecordRef.GetTable(ToSalesHeader);
+        
+        // Clear Shpfy Order Id field (30100) if it exists
+        if RecordRef.FieldExist(30100) then begin
+            FieldRef := RecordRef.Field(30100);
+            FieldRef.Value := 0;
+        end;
+        
+        // Clear Shpfy Order No. field (30101) if it exists
+        if RecordRef.FieldExist(30101) then begin
+            FieldRef := RecordRef.Field(30101);
+            FieldRef.Value := '';
+        end;
+        
+        RecordRef.SetTable(ToSalesHeader);
+    end;
+}
